import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const MyTasks = () => {
  const { user } = useAuth();
  const { tasks, updateTaskProgress, finishTask } = useData(); // Lấy hàm finishTask
  
  const [inputs, setInputs] = useState({});
  const [reasons, setReasons] = useState({});

  // 1. Lọc task của user
  const myTasks = tasks.filter(t => t.assigneeId === user.id);

  // 2. Phân loại Task
  const now = new Date();
  
  const categorizedTasks = {
    inProgress: [],
    upcoming: [],
    completed: []
  };

  myTasks.forEach(task => {
    const start = new Date(task.startTime);
    
    // Logic phân loại:
    // Nếu status là completed -> Đã hoàn thành
    // Nếu chưa đến ngày start -> Sắp đến
    // Còn lại -> Đang diễn ra
    if (task.status === 'completed') {
      categorizedTasks.completed.push(task);
    } else if (now < start) {
      categorizedTasks.upcoming.push(task);
    } else {
      categorizedTasks.inProgress.push(task);
    }
  });

  // 3. Sắp xếp mục "Đang diễn ra": Gần deadline nhất lên đầu (ưu tiên)
  categorizedTasks.inProgress.sort((a, b) => new Date(a.endTime) - new Date(b.endTime));

  // --- Xử lý Cập nhật Tiến độ ---
  const handleUpdateClick = (task) => {
      const newProg = inputs[task.id] !== undefined ? parseInt(inputs[task.id]) : task.progress;
      const reason = reasons[task.id] || task.reason || '';

      if (newProg < 90 && !reason.trim()) {
          alert("CẢNH BÁO: Tiến độ dưới 90% bắt buộc phải nhập lý do giải trình!");
          return;
      }
      updateTaskProgress(task.id, newProg, reason);
      alert("Cập nhật tiến độ thành công!");
  };

  // --- Xử lý Kết thúc Task ---
  const handleFinishClick = (task) => {
    if(window.confirm(`Xác nhận hoàn thành nhiệm vụ "${task.title}"? Kết quả sẽ được ghi nhận vào hiệu suất.`)){
      finishTask(task.id); // Gọi hàm finishTask để cập nhật status và finishedAt
    }
  };

  // Component hiển thị từng Task Card
  const TaskCard = ({ task, isCompletedMode = false }) => {
    const deadline = new Date(task.endTime);
    // Logic "Quá hạn": Quá deadline VÀ chưa hoàn thành
    const isOverdue = now > deadline && !isCompletedMode;
    // Logic "Gấp": Còn dưới 24h VÀ chưa hoàn thành VÀ chưa quá hạn
    const isUrgent = !isOverdue && !isCompletedMode && (deadline - now) < 86400000; 

    return (
        <div style={{ 
            border: isOverdue ? '2px solid red' : (isUrgent ? '2px solid orange' : '1px solid #ccc'),
            padding: '20px', borderRadius: '8px', background: 'white', marginBottom: '15px',
            opacity: isCompletedMode ? 0.7 : 1,
            position: 'relative'
        }}>
            {/* LABELS */}
            <div style={{display:'flex', justifyContent:'space-between', alignItems:'flex-start'}}>
                <h3 style={{margin:0, color: isCompletedMode ? '#059669' : '#003366'}}>{task.title}</h3>
                <div style={{display:'flex', gap:'5px', flexWrap:'wrap', justifyContent:'flex-end'}}>
                    {isCompletedMode && <span style={{background:'#059669', color:'white', padding:'4px 8px', borderRadius:'4px', fontSize:'0.75rem', fontWeight:'bold'}}>ĐÃ HOÀN THÀNH</span>}
                    {isUrgent && <span style={{background:'orange', color:'white', padding:'4px 8px', borderRadius:'4px', fontSize:'0.75rem', fontWeight:'bold'}}>CẦN HOÀN THÀNH GẤP</span>}
                    {isOverdue && <span style={{background:'red', color:'white', padding:'4px 8px', borderRadius:'4px', fontSize:'0.75rem', fontWeight:'bold'}}>QUÁ HẠN</span>}
                </div>
            </div>
            
            {isOverdue && <div style={{color: 'red', fontWeight: 'bold', marginTop: '10px', background:'#fff1f0', padding:'5px', borderRadius:'4px'}}>KỶ LUẬT ÁP DỤNG: {task.disciplineName || 'Chưa quy định'}</div>}

            <p style={{fontSize:'0.9rem', color:'#555'}}>
                <strong>Bắt đầu:</strong> {new Date(task.startTime).toLocaleString()} <br/>
                <strong>Deadline:</strong> {new Date(task.endTime).toLocaleString()}
            </p>
            <p style={{fontSize:'0.9rem'}}><strong>Vai trò:</strong> {task.assignedRole} | <strong>Chi trả:</strong> {task.paymentType}</p>
            <p style={{fontStyle:'italic', color:'#666', background:'#f9f9f9', padding:'8px', borderRadius:'4px'}}>{task.description}</p>

            <hr style={{margin:'15px 0', borderTop:'1px solid #eee'}}/>
            
            {/* CONTROL AREA */}
            <label>Mức độ hoàn thành: <strong>{task.progress}%</strong></label>
            <input type="range" min="0" max="100" value={task.progress} disabled style={{width:'100%', opacity: 0.6, margin: '10px 0'}} />
            
            {!isCompletedMode && (
                <>
                    <div style={{display: 'flex', gap: '10px', alignItems: 'center', background:'#f9fafb', padding:'10px', borderRadius:'6px'}}>
                        <span style={{fontSize:'0.9rem'}}>Nhập % mới:</span>
                        <input 
                            type="number" min="0" max="100" 
                            value={inputs[task.id] !== undefined ? inputs[task.id] : task.progress}
                            onChange={e => setInputs({...inputs, [task.id]: e.target.value})}
                            style={{padding:'5px', width: '60px', fontWeight: 'bold', border:'1px solid #ccc', borderRadius:'4px'}}
                        />
                    </div>

                    {((inputs[task.id] !== undefined ? inputs[task.id] : task.progress) < 90) && (
                        <div style={{marginTop:'10px'}}>
                            <div style={{color:'orange', fontSize:'0.8rem', marginBottom:'4px'}}>* Bắt buộc nhập lý do (Tiến độ &lt; 90%)</div>
                            <textarea 
                                placeholder="Giải trình lý do..."
                                value={reasons[task.id] !== undefined ? reasons[task.id] : (task.reason || '')}
                                onChange={e => setReasons({...reasons, [task.id]: e.target.value})}
                                style={{width:'100%', height:'60px', borderColor: 'orange', padding:'8px', boxSizing:'border-box', borderRadius:'4px'}}
                            />
                        </div>
                    )}

                    <div style={{display:'flex', gap:'10px', marginTop:'15px'}}>
                        <button onClick={() => handleUpdateClick(task)} style={{flex:1, background:'#003366', color:'white', padding:'10px', border:'none', borderRadius:'4px', cursor:'pointer', fontWeight:'bold'}}>
                            Cập nhật tiến độ
                        </button>
                        <button onClick={() => handleFinishClick(task)} style={{flex:1, background:'#059669', color:'white', padding:'10px', border:'none', borderRadius:'4px', cursor:'pointer', fontWeight:'bold'}}>
                            Kết thúc
                        </button>
                    </div>
                </>
            )}
            
            {isCompletedMode && task.finishedAt && (
                <div style={{marginTop:'10px', fontSize:'0.85rem', color:'#059669', fontWeight:'bold', textAlign:'center'}}>
                    ✅ Đã kết thúc lúc: {new Date(task.finishedAt).toLocaleString()}
                </div>
            )}
        </div>
    );
  };

  return (
    <div>
      <h2 style={{ color: '#003366' }}>Nhiệm vụ của tôi</h2>
      
      {/* SECTION 1: ĐANG DIỄN RA */}
      <div style={{marginBottom: '30px'}}>
          <h3 style={{color:'#d97706', borderBottom:'2px solid #d97706', display:'inline-block', paddingBottom:'5px'}}>🔥 Đang diễn ra ({categorizedTasks.inProgress.length})</h3>
          <div style={{marginTop:'15px'}}>
              {categorizedTasks.inProgress.length === 0 ? <p style={{color:'#999'}}>Không có nhiệm vụ đang diễn ra.</p> : 
                categorizedTasks.inProgress.map(task => <TaskCard key={task.id} task={task} />)
              }
          </div>
      </div>

      {/* SECTION 2: SẮP ĐẾN */}
      <div style={{marginBottom: '30px'}}>
          <h3 style={{color:'#003366', borderBottom:'2px solid #003366', display:'inline-block', paddingBottom:'5px'}}>⏳ Sắp đến ({categorizedTasks.upcoming.length})</h3>
          <div style={{marginTop:'15px'}}>
              {categorizedTasks.upcoming.length === 0 ? <p style={{color:'#999'}}>Không có nhiệm vụ sắp tới.</p> : 
                categorizedTasks.upcoming.map(task => <TaskCard key={task.id} task={task} />)
              }
          </div>
      </div>

      {/* SECTION 3: ĐÃ HOÀN THÀNH */}
      <div style={{marginBottom: '30px'}}>
          <h3 style={{color:'#059669', borderBottom:'2px solid #059669', display:'inline-block', paddingBottom:'5px'}}>✅ Đã hoàn thành ({categorizedTasks.completed.length})</h3>
          <div style={{marginTop:'15px'}}>
              {categorizedTasks.completed.length === 0 ? <p style={{color:'#999'}}>Chưa có nhiệm vụ hoàn thành.</p> : 
                categorizedTasks.completed.map(task => <TaskCard key={task.id} task={task} isCompletedMode={true} />)
              }
          </div>
      </div>

    </div>
  );
};

export default MyTasks;
